customCSS:
/* Tokyo Night - City Lights */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 25% 5%, rgba(122, 162, 247, 0.20), transparent),
    radial-gradient(ellipse 500px 350px at 75% 85%, rgba(187, 154, 247, 0.14), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(122, 162, 247, 0.15);
  background: rgba(36, 40, 59, 0.9);
}

.stat-card::before {
  background: linear-gradient(90deg, #7aa2f7, #bb9af7, #ff007c);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(187, 154, 247, 0.3);
  box-shadow: 0 4px 24px rgba(122, 162, 247, 0.12);
}

.stat-value {
  text-shadow: 0 0 15px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #7aa2f7, #bb9af7, #ff007c);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(36, 40, 59, 0.7);
  border: 1px solid rgba(122, 162, 247, 0.1);
}

.miner-card:hover {
  border-color: rgba(158, 206, 106, 0.2);
}
